HTML_PAGE = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>OMC Agent — oh-my-claudecode lite</title>\n<link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;700&family=Clash+Display:wght@400;500;600;700&family=Syne:wght@400;700;800&display=swap" rel="stylesheet">\n<style>\n:root {\n  --bg: #080c12;\n  --surface: #0d1520;\n  --border: rgba(255,255,255,0.07);\n  --border-bright: rgba(0,255,140,0.2);\n  --green: #00ff8c;\n  --blue: #4db8ff;\n  --gold: #ffd700;\n  --pink: #ff6eb4;\n  --purple: #c878ff;\n  --orange: #ff9f43;\n  --text: rgba(255,255,255,0.88);\n  --muted: rgba(255,255,255,0.35);\n  --dim: rgba(255,255,255,0.12);\n}\n\n* { margin:0; padding:0; box-sizing:border-box; }\n\nbody {\n  background: var(--bg);\n  color: var(--text);\n  font-family: \'JetBrains Mono\', monospace;\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n  overflow: hidden;\n}\n\n/* ── SCANLINES OVERLAY ── */\nbody::before {\n  content:\'\';\n  position:fixed; inset:0;\n  background: repeating-linear-gradient(\n    0deg,\n    transparent,\n    transparent 2px,\n    rgba(0,0,0,0.03) 2px,\n    rgba(0,0,0,0.03) 4px\n  );\n  pointer-events:none;\n  z-index:999;\n}\n\n/* ── HEADER ── */\nheader {\n  padding: 16px 28px;\n  border-bottom: 1px solid var(--border);\n  display: flex;\n  align-items: center;\n  gap: 20px;\n  background: rgba(0,0,0,0.4);\n  backdrop-filter: blur(20px);\n  flex-shrink: 0;\n}\n\n.logo {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n}\n.logo-icon {\n  width: 32px; height: 32px;\n  background: linear-gradient(135deg, var(--green), var(--blue));\n  border-radius: 8px;\n  display: flex; align-items: center; justify-content: center;\n  font-size: 16px;\n  font-weight: 700;\n  color: #080c12;\n  font-family: \'Syne\', sans-serif;\n  flex-shrink: 0;\n}\n.logo-text {\n  font-family: \'Syne\', sans-serif;\n  font-weight: 800;\n  font-size: 15px;\n  letter-spacing: 0.5px;\n}\n.logo-text span { color: var(--green); }\n.logo-sub {\n  font-size: 10px;\n  color: var(--muted);\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  margin-top: 1px;\n}\n\n.header-status {\n  margin-left: auto;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  font-size: 11px;\n  color: var(--muted);\n  letter-spacing: 1px;\n}\n.status-dot {\n  width: 7px; height: 7px;\n  border-radius: 50%;\n  background: var(--green);\n  box-shadow: 0 0 8px var(--green);\n  animation: pulse 2s ease-in-out infinite;\n}\n@keyframes pulse {\n  0%,100%{ opacity:1; box-shadow:0 0 8px var(--green); }\n  50%{ opacity:0.4; box-shadow:0 0 3px var(--green); }\n}\n.status-dot.inactive { background: var(--muted); box-shadow: none; animation: none; }\n\n/* ── MAIN LAYOUT ── */\n.app {\n  display: grid;\n  grid-template-columns: 220px 1fr;\n  grid-template-rows: 1fr 140px;\n  height: calc(100vh - 65px);\n  gap: 0;\n}\n\n/* ── SIDEBAR ── */\n.sidebar {\n  grid-row: 1 / 3;\n  border-right: 1px solid var(--border);\n  background: rgba(0,0,0,0.2);\n  padding: 16px 12px;\n  overflow-y: auto;\n  display: flex;\n  flex-direction: column;\n  gap: 6px;\n}\n\n.sidebar-label {\n  font-size: 10px;\n  color: var(--muted);\n  letter-spacing: 3px;\n  text-transform: uppercase;\n  padding: 0 8px;\n  margin-bottom: 4px;\n  margin-top: 8px;\n}\n.sidebar-label:first-child { margin-top: 0; }\n\n.agent-btn {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 10px 12px;\n  border-radius: 8px;\n  border: 1px solid transparent;\n  background: transparent;\n  cursor: pointer;\n  transition: all 0.15s ease;\n  width: 100%;\n  text-align: left;\n}\n.agent-btn:hover {\n  background: rgba(255,255,255,0.04);\n  border-color: var(--border);\n}\n.agent-btn.active {\n  border-color: var(--agent-color, var(--green));\n  background: rgba(0,255,140,0.05);\n  box-shadow: 0 0 16px rgba(0,255,140,0.06);\n}\n.agent-dot {\n  width: 8px; height: 8px;\n  border-radius: 50%;\n  background: var(--agent-color, var(--green));\n  flex-shrink: 0;\n}\n.agent-name {\n  font-size: 12px;\n  color: var(--text);\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;\n}\n.auto-badge {\n  margin-left: auto;\n  font-size: 9px;\n  background: rgba(0,255,140,0.1);\n  border: 1px solid rgba(0,255,140,0.2);\n  color: var(--green);\n  padding: 2px 6px;\n  border-radius: 4px;\n  letter-spacing: 1px;\n  flex-shrink: 0;\n}\n\n.sidebar-divider {\n  height: 1px;\n  background: var(--border);\n  margin: 8px 0;\n}\n\n/* Mode selector */\n.mode-btn {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 12px;\n  border-radius: 6px;\n  border: 1px solid transparent;\n  background: transparent;\n  cursor: pointer;\n  width: 100%;\n  text-align: left;\n  transition: all 0.15s;\n}\n.mode-btn:hover { background: rgba(255,255,255,0.03); border-color: var(--border); }\n.mode-btn.active { border-color: rgba(77,184,255,0.3); background: rgba(77,184,255,0.05); }\n.mode-icon { font-size: 13px; }\n.mode-name { font-size: 11px; color: var(--muted); }\n.mode-btn.active .mode-name { color: var(--blue); }\n\n/* ── OUTPUT AREA ── */\n.output {\n  background: var(--bg);\n  overflow-y: auto;\n  padding: 20px 28px;\n  display: flex;\n  flex-direction: column;\n  gap: 0;\n  font-size: 13px;\n  line-height: 1.7;\n}\n\n/* Welcome screen */\n.welcome {\n  margin: auto;\n  text-align: center;\n  max-width: 500px;\n}\n.welcome-logo {\n  font-size: 48px;\n  margin-bottom: 16px;\n}\n.welcome h2 {\n  font-family: \'Syne\', sans-serif;\n  font-size: 22px;\n  font-weight: 800;\n  color: var(--text);\n  margin-bottom: 10px;\n}\n.welcome h2 span { color: var(--green); }\n.welcome p {\n  font-size: 12px;\n  color: var(--muted);\n  line-height: 1.8;\n  margin-bottom: 24px;\n}\n.example-chips {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  justify-content: center;\n}\n.chip {\n  font-size: 11px;\n  background: rgba(255,255,255,0.04);\n  border: 1px solid var(--border);\n  border-radius: 100px;\n  padding: 6px 14px;\n  color: var(--muted);\n  cursor: pointer;\n  transition: all 0.15s;\n}\n.chip:hover {\n  border-color: var(--green);\n  color: var(--green);\n  background: rgba(0,255,140,0.05);\n}\n\n/* Message blocks */\n.msg-block {\n  margin-bottom: 4px;\n  animation: fadeIn 0.2s ease;\n}\n@keyframes fadeIn { from{opacity:0;transform:translateY(4px)} to{opacity:1;transform:none} }\n\n.agent-header {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 8px 0 4px;\n  font-size: 11px;\n  color: var(--muted);\n  letter-spacing: 1px;\n  text-transform: uppercase;\n  border-top: 1px solid var(--border);\n  margin-top: 12px;\n}\n.agent-header:first-child { border-top: none; margin-top: 0; }\n.agent-header-dot {\n  width: 6px; height: 6px;\n  border-radius: 50%;\n}\n.agent-header-line {\n  flex: 1;\n  height: 1px;\n  background: var(--border);\n}\n.agent-content {\n  padding: 8px 0 4px 16px;\n  color: var(--text);\n  white-space: pre-wrap;\n  word-break: break-word;\n}\n\n/* Typed text effect on content */\n.agent-content strong { color: #fff; font-weight: 700; }\n.agent-content em { color: var(--muted); }\n.agent-content code {\n  background: rgba(255,255,255,0.07);\n  padding: 1px 6px;\n  border-radius: 4px;\n  font-size: 12px;\n  color: var(--green);\n}\n\n/* System messages */\n.sys-msg {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 6px 0;\n  font-size: 11px;\n  color: var(--muted);\n  letter-spacing: 0.5px;\n}\n.sys-msg.orchestrating { color: var(--blue); }\n.sys-msg.decision { color: var(--gold); }\n.sys-msg.complete { color: var(--green); }\n.sys-msg.error { color: #ff5f5f; }\n\n/* Decision card */\n.decision-card {\n  margin: 8px 0;\n  padding: 12px 16px;\n  background: rgba(255,215,0,0.04);\n  border: 1px solid rgba(255,215,0,0.15);\n  border-radius: 10px;\n  font-size: 12px;\n}\n.decision-card .d-row {\n  display: flex;\n  gap: 8px;\n  margin-bottom: 4px;\n  align-items: flex-start;\n}\n.decision-card .d-label {\n  color: var(--muted);\n  min-width: 80px;\n  flex-shrink: 0;\n}\n.decision-card .d-value { color: var(--text); }\n.decision-card .d-value.agent { color: var(--gold); font-weight: 700; }\n\n/* User message */\n.user-msg {\n  padding: 10px 14px;\n  background: rgba(77,184,255,0.06);\n  border: 1px solid rgba(77,184,255,0.15);\n  border-radius: 10px;\n  margin: 12px 0 4px;\n  font-size: 13px;\n  color: rgba(255,255,255,0.7);\n}\n.user-msg::before {\n  content: \'▸ \';\n  color: var(--blue);\n  font-weight: 700;\n}\n\n/* Cursor blink */\n.cursor {\n  display: inline-block;\n  width: 8px; height: 14px;\n  background: var(--green);\n  margin-left: 2px;\n  vertical-align: text-bottom;\n  animation: blink 1s ease-in-out infinite;\n}\n@keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }\n\n/* ── INPUT AREA ── */\n.input-area {\n  border-top: 1px solid var(--border);\n  background: rgba(0,0,0,0.5);\n  backdrop-filter: blur(20px);\n  padding: 16px 28px;\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n}\n\n.input-row {\n  display: flex;\n  gap: 10px;\n  align-items: flex-end;\n}\n\n.input-wrapper {\n  flex: 1;\n  background: rgba(255,255,255,0.04);\n  border: 1px solid var(--border);\n  border-radius: 10px;\n  padding: 10px 14px;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  transition: border-color 0.15s;\n}\n.input-wrapper:focus-within {\n  border-color: rgba(0,255,140,0.3);\n  background: rgba(0,255,140,0.03);\n}\n.input-prompt {\n  color: var(--green);\n  font-size: 14px;\n  flex-shrink: 0;\n}\n#task-input {\n  flex: 1;\n  background: transparent;\n  border: none;\n  outline: none;\n  color: var(--text);\n  font-family: \'JetBrains Mono\', monospace;\n  font-size: 13px;\n  resize: none;\n  min-height: 20px;\n  max-height: 80px;\n  line-height: 1.5;\n}\n#task-input::placeholder { color: var(--muted); }\n\n.send-btn {\n  padding: 10px 22px;\n  background: linear-gradient(135deg, #00ff8c, #00c96b);\n  border: none;\n  border-radius: 10px;\n  color: #080c12;\n  font-family: \'JetBrains Mono\', monospace;\n  font-size: 12px;\n  font-weight: 700;\n  cursor: pointer;\n  letter-spacing: 1px;\n  transition: all 0.15s;\n  flex-shrink: 0;\n}\n.send-btn:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(0,255,140,0.3); }\n.send-btn:active { transform: none; }\n.send-btn:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }\n\n.input-meta {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  font-size: 10px;\n  color: var(--muted);\n  letter-spacing: 1px;\n}\n.input-meta span { display: flex; align-items: center; gap: 5px; }\n.selected-agent-chip {\n  background: rgba(0,255,140,0.08);\n  border: 1px solid rgba(0,255,140,0.2);\n  color: var(--green);\n  padding: 2px 10px;\n  border-radius: 100px;\n  font-size: 10px;\n}\n</style>\n</head>\n<body>\n\n<header>\n  <div class="logo">\n    <div class="logo-icon">O</div>\n    <div>\n      <div class="logo-text">oh-my-<span>claudecode</span> lite</div>\n      <div class="logo-sub">Multi-Agent Orchestration</div>\n    </div>\n  </div>\n  <div class="header-status">\n    <div class="status-dot" id="conn-dot"></div>\n    <span id="conn-label">CONNECTING</span>\n  </div>\n</header>\n\n<div class="app">\n\n  <!-- SIDEBAR -->\n  <aside class="sidebar">\n    <div class="sidebar-label">Mode</div>\n    <button class="mode-btn active" data-mode="auto" onclick="setMode(\'auto\',this)">\n      <span class="mode-icon">🧠</span>\n      <span class="mode-name">Auto (Orchestrator)</span>\n    </button>\n    <button class="mode-btn" data-mode="direct" onclick="setMode(\'direct\',this)">\n      <span class="mode-icon">🎯</span>\n      <span class="mode-name">Direct Agent</span>\n    </button>\n\n    <div class="sidebar-divider"></div>\n    <div class="sidebar-label">Agents</div>\n\n    <button class="agent-btn" data-agent="autopilot" style="--agent-color:#00ff8c" onclick="selectAgent(\'autopilot\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">🚀 Autopilot</div>\n      <div class="auto-badge">AUTO</div>\n    </button>\n    <button class="agent-btn" data-agent="planner" style="--agent-color:#4db8ff" onclick="selectAgent(\'planner\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">📋 Planner</div>\n    </button>\n    <button class="agent-btn" data-agent="ralph" style="--agent-color:#ffd700" onclick="selectAgent(\'ralph\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">🔄 Ralph</div>\n    </button>\n    <button class="agent-btn" data-agent="researcher" style="--agent-color:#ff6eb4" onclick="selectAgent(\'researcher\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">🔍 Researcher</div>\n    </button>\n    <button class="agent-btn" data-agent="coder" style="--agent-color:#c878ff" onclick="selectAgent(\'coder\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">💻 Coder</div>\n    </button>\n    <button class="agent-btn" data-agent="eco" style="--agent-color:#ff9f43" onclick="selectAgent(\'eco\',this)">\n      <div class="agent-dot"></div>\n      <div class="agent-name">⚡ Ecomode</div>\n    </button>\n\n    <div class="sidebar-divider"></div>\n    <div class="sidebar-label">Quick Tasks</div>\n\n    <button class="mode-btn" onclick="quickTask(\'Plan my AutoContent Engine improvements for SEO\')">\n      <span class="mode-icon">✍️</span><span class="mode-name">Content SEO Plan</span>\n    </button>\n    <button class="mode-btn" onclick="quickTask(\'Research best monetization strategies for finance blogs in 2026\')">\n      <span class="mode-icon">💰</span><span class="mode-name">Monetization Research</span>\n    </button>\n    <button class="mode-btn" onclick="quickTask(\'Write Python code for auto internal linking between blog posts\')">\n      <span class="mode-icon">🔗</span><span class="mode-name">Internal Linking Code</span>\n    </button>\n    <button class="mode-btn" onclick="quickTask(\'Plan PropAI real estate portal for Moldova market\')">\n      <span class="mode-icon">🏠</span><span class="mode-name">PropAI Plan</span>\n    </button>\n  </aside>\n\n  <!-- OUTPUT -->\n  <main class="output" id="output">\n    <div class="welcome" id="welcome">\n      <div class="welcome-logo">🤖</div>\n      <h2>oh-my-<span>claudecode</span> lite</h2>\n      <p>Multi-agent orchestration powered by Claude API.<br>\n      The Orchestrator analyses your task and routes it<br>\n      to the best agent automatically.</p>\n      <div class="example-chips">\n        <div class="chip" onclick="useChip(this)">autopilot: build a REST API</div>\n        <div class="chip" onclick="useChip(this)">plan my SaaS product</div>\n        <div class="chip" onclick="useChip(this)">research AI monetization 2026</div>\n        <div class="chip" onclick="useChip(this)">ralph: fix all bugs in my code</div>\n        <div class="chip" onclick="useChip(this)">eco: summarize this article</div>\n      </div>\n    </div>\n  </main>\n\n  <!-- INPUT -->\n  <div class="input-area">\n    <div class="input-row">\n      <div class="input-wrapper">\n        <span class="input-prompt">$</span>\n        <textarea id="task-input" placeholder="Describe your task... (autopilot: ..., ralph: ..., eco: ...)" rows="1"></textarea>\n      </div>\n      <button class="send-btn" id="send-btn" onclick="sendTask()">RUN ▶</button>\n    </div>\n    <div class="input-meta">\n      <span>MODE: <span id="mode-label" class="selected-agent-chip">AUTO</span></span>\n      <span id="agent-label-wrap" style="display:none">AGENT: <span id="agent-label" class="selected-agent-chip">autopilot</span></span>\n      <span style="margin-left:auto">Enter ↵ to send</span>\n    </div>\n  </div>\n\n</div>\n\n<script>\nconst WS_URL = `${location.protocol === \'https:\' ? \'wss\' : \'ws\'}://${location.host}/ws/${Math.random().toString(36).slice(2)}`;\nlet ws = null;\nlet running = false;\nlet currentAgentEl = null;\nlet currentMode = \'auto\';\nlet selectedAgent = null;\n\n// ── WEBSOCKET ──\nfunction connect() {\n  ws = new WebSocket(WS_URL);\n\n  ws.onopen = () => {\n    document.getElementById(\'conn-dot\').className = \'status-dot\';\n    document.getElementById(\'conn-label\').textContent = \'READY\';\n  };\n\n  ws.onclose = () => {\n    document.getElementById(\'conn-dot\').className = \'status-dot inactive\';\n    document.getElementById(\'conn-label\').textContent = \'OFFLINE\';\n    setTimeout(connect, 2000);\n  };\n\n  ws.onerror = () => {\n    document.getElementById(\'conn-label\').textContent = \'ERROR\';\n  };\n\n  ws.onmessage = (e) => {\n    const data = JSON.parse(e.data);\n    handleMsg(data);\n  };\n}\n\nfunction handleMsg(data) {\n  const out = document.getElementById(\'output\');\n\n  if (data.type === \'orchestrating\') {\n    appendSys(\'orchestrating\', \'🧠 \' + data.text);\n    return;\n  }\n\n  if (data.type === \'decision\') {\n    const card = document.createElement(\'div\');\n    card.className = \'decision-card msg-block\';\n    card.innerHTML = `\n      <div class="d-row"><span class="d-label">AGENT:</span><span class="d-value agent">${data.agent.toUpperCase()}</span></div>\n      <div class="d-row"><span class="d-label">MODE:</span><span class="d-value">${data.mode}</span></div>\n      <div class="d-row"><span class="d-label">REASON:</span><span class="d-value">${data.reasoning}</span></div>\n      <div class="d-row"><span class="d-label">TASK:</span><span class="d-value">${data.task_refined}</span></div>\n    `;\n    out.appendChild(card);\n    scrollDown();\n    return;\n  }\n\n  if (data.type === \'agent_start\') {\n    const header = document.createElement(\'div\');\n    header.className = \'agent-header msg-block\';\n    header.innerHTML = `\n      <div class="agent-header-dot" style="background:${data.color};box-shadow:0 0 8px ${data.color}40"></div>\n      <span style="color:${data.color}">${data.name}</span>\n      <div class="agent-header-line"></div>\n    `;\n    out.appendChild(header);\n\n    const content = document.createElement(\'div\');\n    content.className = \'agent-content\';\n    content.id = \'ac-\' + data.agent + \'-\' + Date.now();\n    const cursor = document.createElement(\'span\');\n    cursor.className = \'cursor\';\n    cursor.id = \'cursor-active\';\n    content.appendChild(cursor);\n    out.appendChild(content);\n    currentAgentEl = content;\n    scrollDown();\n    return;\n  }\n\n  if (data.type === \'token\') {\n    if (currentAgentEl) {\n      const cursor = currentAgentEl.querySelector(\'.cursor\');\n      const text = document.createTextNode(data.text);\n      if (cursor) {\n        currentAgentEl.insertBefore(text, cursor);\n      } else {\n        currentAgentEl.appendChild(text);\n      }\n      // simple markdown: bold\n      currentAgentEl.innerHTML = currentAgentEl.innerHTML\n        .replace(/\\*\\*(.+?)\\*\\*/g, \'<strong>$1</strong>\')\n        .replace(/`(.+?)`/g, \'<code>$1</code>\');\n      scrollDown();\n    }\n    return;\n  }\n\n  if (data.type === \'agent_done\') {\n    if (currentAgentEl) {\n      const cursor = currentAgentEl.querySelector(\'.cursor\');\n      if (cursor) cursor.remove();\n      currentAgentEl = null;\n    }\n    return;\n  }\n\n  if (data.type === \'complete\') {\n    appendSys(\'complete\', \'✅ Task complete\');\n    setRunning(false);\n    return;\n  }\n\n  if (data.type === \'error\') {\n    appendSys(\'error\', \'❌ \' + (data.text || \'Unknown error\'));\n    setRunning(false);\n    return;\n  }\n}\n\nfunction appendSys(cls, text) {\n  const out = document.getElementById(\'output\');\n  const el = document.createElement(\'div\');\n  el.className = `sys-msg ${cls} msg-block`;\n  el.textContent = text;\n  out.appendChild(el);\n  scrollDown();\n}\n\nfunction scrollDown() {\n  const out = document.getElementById(\'output\');\n  out.scrollTop = out.scrollHeight;\n}\n\n// ── SEND ──\nfunction sendTask() {\n  const input = document.getElementById(\'task-input\');\n  const task = input.value.trim();\n  if (!task || running || !ws || ws.readyState !== 1) return;\n\n  // hide welcome\n  const welcome = document.getElementById(\'welcome\');\n  if (welcome) welcome.remove();\n\n  // show user message\n  const out = document.getElementById(\'output\');\n  const userEl = document.createElement(\'div\');\n  userEl.className = \'user-msg msg-block\';\n  userEl.textContent = task;\n  out.appendChild(userEl);\n\n  setRunning(true);\n  input.value = \'\';\n  input.style.height = \'auto\';\n\n  const payload = { type: \'task\', task };\n  if (currentMode === \'direct\' && selectedAgent) {\n    payload.agent = selectedAgent;\n  }\n  ws.send(JSON.stringify(payload));\n}\n\nfunction setRunning(v) {\n  running = v;\n  document.getElementById(\'send-btn\').disabled = v;\n  document.getElementById(\'conn-dot\').className = v ? \'status-dot\' : \'status-dot\';\n  document.getElementById(\'conn-label\').textContent = v ? \'RUNNING...\' : \'READY\';\n}\n\n// ── MODE / AGENT SELECTION ──\nfunction setMode(mode, btn) {\n  currentMode = mode;\n  document.querySelectorAll(\'.mode-btn\').forEach(b => b.classList.remove(\'active\'));\n  btn.classList.add(\'active\');\n  document.getElementById(\'mode-label\').textContent = mode.toUpperCase();\n  document.getElementById(\'agent-label-wrap\').style.display = mode === \'direct\' ? \'flex\' : \'none\';\n}\n\nfunction selectAgent(agent, btn) {\n  selectedAgent = agent;\n  document.querySelectorAll(\'.agent-btn\').forEach(b => b.classList.remove(\'active\'));\n  btn.classList.add(\'active\');\n  document.getElementById(\'agent-label\').textContent = agent;\n  // auto switch to direct mode\n  if (currentMode !== \'direct\') {\n    setMode(\'direct\', document.querySelector(\'[data-mode="direct"]\'));\n  }\n}\n\nfunction useChip(el) {\n  document.getElementById(\'task-input\').value = el.textContent;\n  document.getElementById(\'task-input\').focus();\n}\n\nfunction quickTask(task) {\n  const input = document.getElementById(\'task-input\');\n  input.value = task;\n  sendTask();\n}\n\n// ── TEXTAREA AUTO-RESIZE ──\ndocument.addEventListener(\'DOMContentLoaded\', () => {\n  const ta = document.getElementById(\'task-input\');\n  ta.addEventListener(\'input\', () => {\n    ta.style.height = \'auto\';\n    ta.style.height = Math.min(ta.scrollHeight, 80) + \'px\';\n  });\n  ta.addEventListener(\'keydown\', (e) => {\n    if (e.key === \'Enter\' && !e.shiftKey) {\n      e.preventDefault();\n      sendTask();\n    }\n  });\n  connect();\n});\n</script>\n</body>\n</html>\n'

